  "sections": {
    "goal": {
      "sectionStatus": "done",
      "items": {
        "statement": "建立 Button、Input、Select 与图标按钮的可审计状态矩阵，并把状态覆盖与明确例外变成可回归的浏览器证据。"
      }
    },
    "scope": {
      "sectionStatus": "done",
      "items": {
        "inScope": [
          "在真实消费者夹具中呈现 default、hover、focus-visible、disabled、loading、error、empty、selected 等适用状态。",
          "以双主题、compact/data-dense/lg/xl 视口运行截图与 axe。",
          "生成组件×状态×主题×视口覆盖清单和例外统计。"
        ],
        "outOfScope": [
          "新增公共组件 API。",
          "私有 registry 发布。"
        ]
      }
    },
    "inputs": {
      "sectionStatus": "done",
      "items": {
        "researchEvidence": "R-SWUI-001 缺口复核：现有 fixture 只覆盖少量组件和常态，缺少系统状态矩阵与覆盖基线。",
        "integrationSurface": "examples/ui-consumer/browser.spec.mjs 与 Playwright projects。"
      }
    },
    "dependencies": {
      "sectionStatus": "done",
      "items": {
        "previousSteps": [],
        "externalDependencies": [
          "Bun 1.3.14",
          "Playwright Chromium",
          "@axe-core/playwright"
        ],
        "userDecisions": [
          "用户选择 Option B 并发送 auto。"
        ],
        "projectResources": [
          "examples/ui-consumer",
          "scripts/verify-packed-consumer.mjs"
        ],
        "axisPositioning": "required: design-system runtime + browser/a11y validation; UI state fixture and test evidence share one invariant.",
        "axisSplitSnapshot": "本 Step 聚合状态夹具、矩阵与统计，因为三者必须共同证明每个状态实际可渲染且可审计。",
        "temporaryArtifactLifecycle": "not-applicable：仅使用已有 Playwright 输出目录，不创建长期临时交接物。"
      }
    },
    "implementation-ready-brief": {
      "sectionStatus": "done",
      "items": {
        "problemDefinition": "现有浏览器矩阵只验证少数常态组件，无法证明核心组件的状态面在主题和断点下均可用。",
        "requirementsDefinition": "为核心组件建立稳定状态夹具、矩阵测试、截图/axe 证据和例外统计；每项例外必须有原因。",
        "nonGoals": [
          "不扩张组件 API。",
          "不把 hover 伪状态伪造成浏览器无法验证的事实。"
        ],
        "plainLanguage": "让每个用户可见状态都有一张可复跑的证据表，而不是只靠默认外观。",
        "candidateOptions": {
          "A": "只扩展现有常态快照。",
          "B": "建立命名状态夹具、矩阵清单与浏览器断言。"
        },
        "recommendedOption": {
          "option": "B",
          "rationale": "能同时捕获状态回归、可访问性回归和覆盖退化。"
        },
        "openDecisions": "none；状态集合由组件现有公开 props/语义决定。",
        "granularityDecision": "fine-enough：夹具、测试和统计共享同一状态覆盖不变量；若新增独立组件域或视觉审查工具，再拆分。",
        "implementationPlan": [
          "盘点核心组件的可表达状态。",
          "构建可访问的状态夹具和显式矩阵元数据。",
          "增加 Playwright 截图、axe 与覆盖统计断言。",
          "将例外及其原因写入文档。"
        ],
        "testCaseDesign": "每个矩阵元至少映射一个真实 DOM 状态；主题/视口以现有 projects 交叉；axe 覆盖可访问性。",
        "acceptanceToTestMapping": "AC1/AC2→Playwright 矩阵与截图；AC3→统计脚本；AC4→例外清单校验。",
        "regressionTestDesign": "新增状态或删除状态时矩阵断言与快照立即失败。",
        "coverageAssessment": "target-driven",
        "residualRisk": "原生 hover/focus 的视觉差异仍受浏览器平台影响，使用语义状态和截图基线降低风险。",
        "readiness": {
          "readiness": "Yes",
          "reason": "已存在消费者、Playwright projects、axe 和基线命令。"
        }
      }
    },
    "implementation-record": {
      "sectionStatus": "done",
      "items": {
        "executionContract": {
          "expectedChangeSurface": "examples/ui-consumer state fixtures, Playwright matrix, screenshots, and quality documentation; no public API change.",
          "acceptanceCriteria": "Button/Input/Select/icon states receive light/dark × compact/data-dense/lg/xl visual and axe evidence, including actual hover and disabled Select.",
          "validationEvidenceRequired": "Consumer typecheck, static contract, production build, normal Playwright matrix, and packed-consumer browser matrix.",
          "rollbackNotes": "Revert the fixture/test/doc changes and generated project screenshot baselines together."
        },
        "implementationSummary": {
          "whatChanged": "Added named Button, icon-button, Input, Select, empty, and ThemeControl-adjacent state fixtures; added DOM/ARIA/hover/screenshot/axe coverage and 24 project screenshot baselines.",
          "whySatisfiesStep": "Every applicable named state now has a rendered fixture and browser evidence across the formal themes and viewport projects.",
          "intentionallyUnchanged": "No @swui/ui public component API, product shell, or routing was changed."
        },
        "changeSurface": {
          "codeAnchors": "examples/ui-consumer/src/main.tsx; examples/ui-consumer/browser.spec.mjs",
          "documentationAnchors": "docs/experience/quality-matrix.md",
          "configAnchors": "examples/ui-consumer/playwright.config.mjs unchanged; existing eight-project matrix retained."
        },
        "executionNotes": {
